#!/usr/bin/env python3
"""
Run from the southorange-site repo root:
  python3 /path/to/game/scripts/fix-thingstodo-page.py
"""
import base64, os, sys

CONTENT_B64 = ""

if len(sys.argv) > 1:
    out = sys.argv[1]
else:
    out = os.path.join(os.getcwd(), 'app', 'guides', 'things-to-do', 'page.tsx')

os.makedirs(os.path.dirname(out), exist_ok=True)
with open(out, 'wb') as f:
    f.write(base64.b64decode(CONTENT_B64))
print(f'Wrote {os.path.getsize(out)} bytes to {out}')
